class Solution:
    def maxScore(self, nums, x):
        n = len(nums)
        NEG = float('-inf')
        dp = [NEG] * n
        dp[0] = nums[0]
        best = dp[0]
        for i in range(1, n):
            for j in range(i):
                if dp[j] == NEG:
                    continue
                cost = 0 if nums[j] % 2 == nums[i] % 2 else x
                cand = dp[j] + nums[i] - cost
                if cand > dp[i]:
                    dp[i] = cand
            best = max(best, dp[i])
        return best

