class Solution:
    def maxScore(self, nums, x):
        NEG = float('-inf')
        if nums[0] % 2 == 0:
            best_even, best_odd = nums[0], NEG
        else:
            best_even, best_odd = NEG, nums[0]
        for i in range(1, len(nums)):
            v = nums[i]
            if v % 2 == 0:
                cand = v + max(best_even, best_odd - x)
                best_even = max(best_even, cand)
            else:
                cand = v + max(best_odd, best_even - x)
                best_odd = max(best_odd, cand)
        return max(best_even, best_odd)

