var maxScore = function(nums, x) {
    const NEG = -Infinity;
    let bestEven, bestOdd;
    if (nums[0] % 2 === 0) {
        bestEven = nums[0]; bestOdd = NEG;
    } else {
        bestEven = NEG; bestOdd = nums[0];
    }
    for (let i = 1; i < nums.length; i++) {
        const v = nums[i];
        if (v % 2 === 0) {
            const cand = v + Math.max(bestEven, bestOdd - x);
            bestEven = Math.max(bestEven, cand);
        } else {
            const cand = v + Math.max(bestOdd, bestEven - x);
            bestOdd = Math.max(bestOdd, cand);
        }
    }
    return Math.max(bestEven, bestOdd);
};
